import { useState } from "react";
import Divider from "../UI/Divider";
import FriendsIcon from "../UI/FriendsIcon";
import classes from "./MainHeader.module.css";
import MainHeaderTab from "./MainHeaderTab";

const MainHeader = () => {
  const [selectedTab, setSelectedTab] = useState("Online");

  const tabState = {
    selectedTab: selectedTab,
    setSelectedTab: setSelectedTab,
  };

  return (
    <section className={classes["main-header"]}>
      <div className={classes["children-container"]}>
        <div className={classes["icon-wrapper"]}>
          <FriendsIcon></FriendsIcon>
        </div>
        <div className={classes["title-wrapper"]}>
          <h1 className={classes["title"]}>Friends</h1>
        </div>
        <Divider></Divider>
        <div className={classes["tab-bar"]}>
          <MainHeaderTab title="Online" tabState={tabState}></MainHeaderTab>
          <MainHeaderTab title="All" tabState={tabState}></MainHeaderTab>
          <MainHeaderTab title="Pending" tabState={tabState}></MainHeaderTab>
          <MainHeaderTab title="Blocked" tabState={tabState}></MainHeaderTab>
          <MainHeaderTab title="Add Friend" tabState={tabState}></MainHeaderTab>
        </div>
      </div>

      <div className={classes["toolbar"]}>
        <div className={classes["icon-wrapper"]}>
          <FriendsIcon></FriendsIcon>
        </div>
        <Divider></Divider>
        <div className={classes["icon-wrapper"]}>
          <FriendsIcon></FriendsIcon>
        </div>
      </div>
    </section>
  );
};

export default MainHeader;
